head.script:
scwin.MSG_SD_ERR_001 = "원화인 경우 소수점을 입력 할 수 없습니다.";
scwin.MSG_SD_ERR_002 = "생성할 요율항목을 선택하십시오.";
scwin.MSG_SD_ERR_003 = "@행, @칼럼의 코드가 일치하지 않습니다.";

scwin.strCtrtNo = "";
scwin.strCommCd = "";
scwin.strCrcCd = "";
scwin.strLobranCd = "";
scwin.strUnitCd = "";
scwin.strDptDistrictCd = "";
scwin.strArvDistrictCd = "";
scwin.regId = "";
scwin.sysAdminYn = 0;
scwin.hid_ctrtRegStsCd = "";
scwin.createFlag = false;

scwin.onpageload = async function() {
    scwin.params = $c.data.getParameter();
    if (scwin.params != null) {
        scwin.strCtrtNo = scwin.params["ctrtNo"] || "";
        scwin.strCommCd = scwin.params["commCd"] || "";
        scwin.strCrcCd = scwin.params["crcCd"] || "";
        scwin.strLobranCd = scwin.params["lobranCd"] || "";
        scwin.strUnitCd = scwin.params["unitCd"] || "";
        scwin.strDptDistrictCd = scwin.params["dptDistrictCd"] || "";
        scwin.strArvDistrictCd = scwin.params["arvDistrictCd"] || "";
    }

    scwin.regId = $c.ses.getUserId();
    scwin.sysAdminYn = $c.ses.getSysAdminYn();

    if ($c.gus.cfIsNull(scwin.strCtrtNo)) {
        await $c.win.alert("계약번호가 없습니다.");
        scwin.f_Close();
        return;
    }

    scwin.createFlag = true;
    await scwin.f_retrieveSelpchItemCd();
    scwin.f_retrieveBase();

    $c.gus.cfDisableObjects([ed_ctrtNo, ed_clntNo, chb_prvsCtrtYn, chb_bizDomTransYn, txt_clntNm, chb_dctrtMchtYn, chb_bizDomStvYn, chb_bizDomStrYn, chb_bizDomStrYn, chb_bizDomTplYn, chb_bizDivCntrYn, chb_bizDivBulkYn, chb_impYn, chb_expYn, chb_domesticYn, acb_ctrtDistrictCd, chb_tplEdiYn, acb_sellClntClsCd, txa_rmk]);
};

scwin.f_retrieveSelpchItemCd = async function() {
    // TODO: sbm_selpchItemCd에 sysCd=CtrtTrfEBC, queryId=retrieveCtrtTransTrfItem, param1=strCtrtNo, param2=21 파라미터 전달 필요
    dma_search.set("ctrtNo", scwin.strCtrtNo);
    await $c.sbm.execute(sbm_selpchItemCd);
};

scwin.f_retrieveBase = async function() {
    dma_search.set("ctrtNo", scwin.strCtrtNo);
    await $c.sbm.execute(sbm_retrieveBase);
};

scwin.f_retrieve = async function() {
    dma_search.set("ctrtNo", scwin.strCtrtNo);
    dma_search.set("selpchItemCd", acb_selpchItemCd.getValue());
    await $c.sbm.execute(sbm_retrieve);
};

scwin.f_retrieveAdd = async function() {
    dma_search.set("ctrtNo", scwin.strCtrtNo);
    dma_search.set("selpchItemCd", acb_selpchItemCd.getValue());
    dma_search.set("commCd", scwin.strCommCd);
    dma_search.set("unitCd", scwin.strUnitCd);
    dma_search.set("crcCd", scwin.strCrcCd);
    dma_search.set("dptDistrictCd", scwin.strDptDistrictCd);
    dma_search.set("arvDistrictCd", scwin.strArvDistrictCd);
    dma_search.set("lobranCd", scwin.strLobranCd);
    await $c.sbm.execute(sbm_retrieveAdd);
};

scwin.f_addRow = async function() {
    if (ds_tariff.getRowCount() == 0) {
        ds_tariff.insertRow();
        let row = ds_tariff.getRowPosition();
        let baseRow = ds_ctrtBase.getRowPosition();
        ds_tariff.setCellData(row, "ctrtNo", ds_ctrtBase.getCellData(baseRow, "ctrtNo"));
        ds_tariff.setCellData(row, "transMdCtrtTrfSeq", "1");
        ds_tariff.setCellData(row, "selpchItemCd", acb_selpchItemCd.getValue());
        ds_tariff.setCellData(row, "crcCd", "KRW");
    } else {
        ds_tariff.insertRow();
        let row = ds_tariff.getRowPosition();
        let baseRow = ds_ctrtBase.getRowPosition();
        ds_tariff.setCellData(row, "ctrtNo", ds_ctrtBase.getCellData(baseRow, "ctrtNo"));
        ds_tariff.setCellData(row, "transMdCtrtTrfSeq", String(ds_tariff.getRowCount() + 1));
        ds_tariff.setCellData(row, "selpchItemCd", acb_selpchItemCd.getValue());
        ds_tariff.setCellData(row, "crcCd", "KRW");
    }
};

scwin.f_DelRow = async function() {
    ds_tariff.removeRow(ds_tariff.getRowPosition());
};

scwin.f_Close = async function() {
    $c.win.closePopup();
};

scwin.f_Save = async function() {
    if (ds_tariff.getUpdatedIndex().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["운송요율"]);
        return false;
    } else {
        if (await scwin.f_reqFieldChk()) {
            await $c.sbm.execute(sbm_save);
            return true;
        } else {
            return false;
        }
    }
};

scwin.f_reqFieldChk = async function() {
    let bChk = true;
    for (let i = 0; i < ds_tariff.getRowCount(); i++) {
        if (ds_tariff.getCellData(i, "ctrtWrkPathSeq").length == 0) {
            gr_tariff.setFocusedCell(i, "ctrtWrkPathSeq");
            await $c.win.alert("계약작업경로는 필수입력입니다.");
            bChk = false;
            break;
        } else if (ds_tariff.getCellData(i, "commNm").length == 0) {
            gr_tariff.setFocusedCell(i, "commNm");
            await $c.win.alert("품명을 정확히 입력하세요.");
            bChk = false;
            break;
        } else if (ds_tariff.getCellData(i, "unitCd").length == 0) {
            gr_tariff.setFocusedCell(i, "unitCd");
            await $c.win.alert("단위를 정확히 입력하세요.");
            bChk = false;
            break;
        } else if (ds_tariff.getCellData(i, "dptDistrictCd").length == 0) {
            gr_tariff.setFocusedCell(i, "dptDistrictNm");
            await $c.win.alert("출발권역은 필수입력입니다.");
            bChk = false;
            break;
        } else if (ds_tariff.getCellData(i, "arvDistrictCd").length == 0) {
            gr_tariff.setFocusedCell(i, "arvDistrictNm");
            await $c.win.alert("도착권역은  필수입력입니다.");
            bChk = false;
            break;
        } else if (ds_tariff.getCellData(i, "crcCd").length == 0) {
            gr_tariff.setFocusedCell(i, "crcCd");
            await $c.win.alert("통화를 정확히 입력하세요.");
            bChk = false;
            break;
        } else if (Number(ds_tariff.getCellData(i, "ctrtTrf")) == 0) {
            gr_tariff.setFocusedCell(i, "ctrtTrf");
            await $c.win.alert("요율은 필수입력입니다. '0' 이상의 값을 입력하세요.");
            bChk = false;
            break;
        } else if ((ds_tariff.getCellData(i, "unitCd") == "VOT" || ds_tariff.getCellData(i, "unitCd") == "VOC")
            && Number(ds_tariff.getCellData(i, "rangeMin")) >= Number(ds_tariff.getCellData(i, "rangeMax"))) {
            gr_tariff.setFocusedCell(i, "rangeMin");
            await $c.win.alert("적용구간을 정확히 입력하세요.");
            bChk = false;
            break;
        }
    }
    return bChk;
};

scwin.f_CopyDataRow = async function(sourceDataset, targetDataset, sourceRow, targetRow, sourceColumns, targetColumns, actionAfterRowAdded) {
    try {
        if (sourceDataset == null) throw "원본 데이터셋이 정의되지 않았습니다.";
        if (targetDataset == null) throw "대상 데이터셋이 정의되지 않았습니다.";

        if (sourceColumns == null) sourceColumns = scwin.f_GetColumnNames(sourceDataset);
        if (targetColumns == null) targetColumns = sourceColumns;
        if (sourceRow == null) sourceRow = sourceDataset.getRowPosition();
        if (targetRow == null) {
            targetRow = scwin.f_AddRowEx(targetDataset);
        }

        for (let i = 0; i < sourceColumns.length; i++) {
            if ($c.gus.cfIsNull(sourceColumns[i]) || $c.gus.cfIsNull(targetColumns[i])) continue;
            targetDataset.setCellData(targetRow, targetColumns[i], sourceDataset.getCellData(sourceRow, sourceColumns[i]));
            if (actionAfterRowAdded != null) eval(actionAfterRowAdded);
        }
        return targetRow;
    } catch (e) {
        await $c.gus.cfAlertMsg("[f_CopyDataRow]" + e);
    }
};

scwin.f_GetColumnNames = async function(dataSet) {
    try {
        if (dataSet == null) throw "데이터셋이 정의되지 않았습니다.";
        let colInfos = dataSet.getColumnIDs();
        if (colInfos == null || colInfos.length == 0) return null;
        return colInfos;
    } catch (e) {
        await $c.win.alert("[f_GetColumnNames] " + e);
    }
};

scwin.f_AddRowEx = async function(dataSet) {
    dataSet.insertRow();
    return dataSet.getRowPosition();
};

scwin.f_WinClose = async function() {
    $c.win.closePopup();
};

scwin.f_Download = async function() {
    let fileName = "운송요율등록양식.csv";
    let filePath = "tn/sd/odrmgnt/cntrodrreg/운송요율등록양식.csv";
    $c.gus.cfDownloadFile(fileName, filePath);
};

scwin.dataSetDebug = async function(dataSet, isDebug) {
    if (isDebug == true) {
        let obj = dataSet;
        let str = "[[[[" + obj.id + "]]]]]\n";
        let colIds = obj.getColumnIDs();
        for (let dsRow = 0; dsRow < obj.getRowCount(); dsRow++) {
            for (let dsCol = 0; dsCol < colIds.length; dsCol++) {
                str += "[" + colIds[dsCol] + "] " + obj.getCellData(dsRow, colIds[dsCol]) + ", ";
            }
            str += "\n\n";
        }
        await $c.win.alert(str);
    }
};

scwin.drmFileSubmit = async function() {
    // TODO: cfDrmUploadFile 파일 업로드 처리 — WebSquare 파일 업로드 컴포넌트로 대체 필요
    $c.gus.cfDrmUploadFile(null, fileUploadGDS, "scwin.f_upload");
};

scwin.f_upload = async function() {
    ds_up_tariff.removeAll();
    ds_TmptranstrfList.removeAll();

    // TODO: 엑셀 업로드 파일 경로를 통한 데이터 로딩 — WebSquare 엑셀 업로드 방식으로 대체 필요
    $c.gus.cfProgressWinOpen();
    $p.setTimeout(function() { scwin.f_Import(); }, {"delay": 1000});
};

scwin.f_Import = async function() {
    if (await scwin.f_AddRowUploaded()) {
        $c.gus.cfProgressWinClose();
        await $c.gus.cfAlertMsg("업로드작업이 완료되었습니다.");
        ds_TmptranstrfList.removeAll();
    }
};

scwin.LPAD = async function(s, c, n) {
    if (!s || !c || s.length >= n) {
        return s;
    }
    let max = (n - s.length) / c.length;
    for (let i = 0; i < max; i++) {
        s = c + s;
    }
    return s;
};

scwin.f_AddRowUploaded = async function() {
    ds_tariff.removeAll();

    let ctrtNoVal = ds_ctrtBase.getCellData(ds_ctrtBase.getRowPosition(), "ctrtNo");
    if (ctrtNoVal == null) ctrtNoVal = "";

    for (let i = 0; i < ds_up_tariff.getRowCount(); i++) {
        ds_TmptranstrfList.insertRow(ds_TmptranstrfList.getRowCount());
        let tmpRow = ds_TmptranstrfList.getRowCount() - 1;
        let colIds = ds_up_tariff.getColumnIDs();
        for (let c = 0; c < colIds.length; c++) {
            ds_TmptranstrfList.setCellData(tmpRow, colIds[c], ds_up_tariff.getCellData(i, colIds[c]));
        }
    }

    for (let i = 0; i < ds_up_tariff.getRowCount(); i++) {
        ds_tariff.insertRow(ds_tariff.getRowCount());
        let tRow = ds_tariff.getRowCount() - 1;
        ds_tariff.setCellData(tRow, "ctrtNo", ds_ctrtBase.getCellData(0, "ctrtNo"));
        ds_tariff.setCellData(tRow, "selpchItemCd", acb_selpchItemCd.getValue());
        ds_tariff.setCellData(tRow, "ctrtWrkPathSeq", ds_TmptranstrfList.getCellData(i, "ctrtWrkPathSeq"));

        let eqKndCd = ds_TmptranstrfList.getCellData(i, "eqKndCd");
        if (eqKndCd != null && eqKndCd != "") {
            eqKndCd = eqKndCd.replace("[", "");
            let eqKndCd_arr = eqKndCd.split(']');
            eqKndCd = eqKndCd_arr[0];
        }

        let eqNrmCd = ds_TmptranstrfList.getCellData(i, "eqNrmCd");
        if (eqNrmCd != null && eqNrmCd != "") {
            eqNrmCd = eqNrmCd.replace("[", "");
            let eqNrmCd_arr = eqNrmCd.split(']');
            eqNrmCd = eqNrmCd_arr[0];
        }

        if (eqNrmCd != null && eqNrmCd.length < 2) {
            eqNrmCd = scwin.LPAD(eqNrmCd, '0', 2);
        }

        ds_tariff.setCellData(tRow, "unitCd", ds_TmptranstrfList.getCellData(i, "unitCd"));
        ds_tariff.setCellData(tRow, "commCd", ds_TmptranstrfList.getCellData(i, "commCd"));
        ds_tariff.setCellData(tRow, "commNm", ds_TmptranstrfList.getCellData(i, "commNm"));
        ds_tariff.setCellData(tRow, "dptDistrictCd", ds_TmptranstrfList.getCellData(i, "dptDistrictCd"));
        ds_tariff.setCellData(tRow, "dptDistrictNm", ds_TmptranstrfList.getCellData(i, "dptDistrictNm"));
        ds_tariff.setCellData(tRow, "arvDistrictCd", ds_TmptranstrfList.getCellData(i, "arvDistrictCd"));
        ds_tariff.setCellData(tRow, "arvDistrictNm", ds_TmptranstrfList.getCellData(i, "arvDistrictNm"));
        ds_tariff.setCellData(tRow, "crcCd", ds_TmptranstrfList.getCellData(i, "crcCd"));
        ds_tariff.setCellData(tRow, "ctrtTrf", ds_TmptranstrfList.getCellData(i, "ctrtTrf"));
        ds_tariff.setCellData(tRow, "eqKndCd", eqKndCd || "");
        ds_tariff.setCellData(tRow, "eqNrmCd", eqNrmCd || "");
        ds_tariff.setCellData(tRow, "lobranCd", ds_TmptranstrfList.getCellData(i, "lobranCd"));
        ds_tariff.setCellData(tRow, "lobranNm", ds_TmptranstrfList.getCellData(i, "lobranNm"));
        ds_tariff.setCellData(tRow, "trfAdptCd", ds_TmptranstrfList.getCellData(i, "trfAdptCd"));
        ds_tariff.setCellData(tRow, "wrkStHh", ds_TmptranstrfList.getCellData(i, "wrkStHh"));
        ds_tariff.setCellData(tRow, "wrkEndHh", ds_TmptranstrfList.getCellData(i, "wrkEndHh"));
        ds_tariff.setCellData(tRow, "rangeMin", ds_TmptranstrfList.getCellData(i, "rangeMin"));
        ds_tariff.setCellData(tRow, "rangeMax", ds_TmptranstrfList.getCellData(i, "rangeMax"));

        if (ds_TmptranstrfList.getCellData(i, "commCd") != "") {
            let rtnList = $c.gus.cfCommonPopUp('retrieveCommInfo_tpro',
                ds_TmptranstrfList.getCellData(i, "commCd"),
                ds_TmptranstrfList.getCellData(i, "commCd"),
                "T",
                null,
                null,
                null,
                null,
                '2,4',
                null,
                null,
                null,
                null,
                null,
                null,
                "품목／품명,품목／품명코드,품목／품명");

            if (rtnList == null) {
                ds_tariff.setCellData(tRow, "commCd", "");
                ds_tariff.setCellData(tRow, "commNm", "");
                await $c.gus.cfAlertMsg(scwin.MSG_SD_ERR_003, [String(i + 1), "품목"]);
                return false;
            } else {
                ds_tariff.setCellData(tRow, "commCd", rtnList[0]);
                ds_tariff.setCellData(tRow, "commNm", rtnList[1]);
            }
        } else if (ds_TmptranstrfList.getCellData(i, "commNm") != "") {
            let rtnList = $c.gus.cfCommonPopUp('retrieveCommInfo_tpro',
                ds_TmptranstrfList.getCellData(i, "commNm"),
                ds_TmptranstrfList.getCellData(i, "commNm"),
                "T",
                null,
                null,
                null,
                null,
                '2,4',
                null,
                null,
                null,
                null,
                null,
                null,
                "품목／품명,품목／품명코드,품목／품명");

            if (rtnList == null) {
                ds_tariff.setCellData(tRow, "commCd", "");
                ds_tariff.setCellData(tRow, "commNm", "");
                await $c.gus.cfAlertMsg(scwin.MSG_SD_ERR_003, [String(i + 1), "품목"]);
                return false;
            } else {
                ds_tariff.setCellData(tRow, "commCd", rtnList[0]);
                ds_tariff.setCellData(tRow, "commNm", rtnList[1]);
            }
        }

        if (ds_TmptranstrfList.getCellData(i, "dptDistrictCd") != "") {
            let rtnList = $c.gus.cfCommonPopUp('retrieveDistrictList_tpro',
                ds_TmptranstrfList.getCellData(i, "dptDistrictCd"),
                ds_TmptranstrfList.getCellData(i, "dptDistrictCd"),
                "T",
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                "출발지,출발지코드,출발지명");

            if (rtnList == null) {
                ds_tariff.setCellData(tRow, "dptDistrictCd", "");
                ds_tariff.setCellData(tRow, "dptDistrictNm", "");
                await $c.gus.cfAlertMsg(scwin.MSG_SD_ERR_003, [String(i + 1), "출발권역"]);
                return false;
            } else {
                ds_tariff.setCellData(tRow, "dptDistrictCd", rtnList[0]);
                ds_tariff.setCellData(tRow, "dptDistrictNm", rtnList[1]);
            }
        } else if (ds_TmptranstrfList.getCellData(i, "dptDistrictNm") != "") {
            let rtnList = $c.gus.cfCommonPopUp('retrieveDistrictList_tpro',
                ds_TmptranstrfList.getCellData(i, "dptDistrictNm"),
                ds_TmptranstrfList.getCellData(i, "dptDistrictNm"),
                "T",
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                "출발지,출발지코드,출발지명");

            if (rtnList == null) {
                ds_tariff.setCellData(tRow, "dptDistrictCd", "");
                ds_tariff.setCellData(tRow, "dptDistrictNm", "");
                await $c.gus.cfAlertMsg(scwin.MSG_SD_ERR_003, [String(i + 1), "출발권역"]);
                return false;
            } else {
                ds_tariff.setCellData(tRow, "dptDistrictCd", rtnList[0]);
                ds_tariff.setCellData(tRow, "dptDistrictNm", rtnList[1]);
            }
        }

        if (ds_TmptranstrfList.getCellData(i, "arvDistrictCd") != "") {
            let rtnList = $c.gus.cfCommonPopUp('retrieveDistrictList_tpro',
                ds_TmptranstrfList.getCellData(i, "arvDistrictCd"),
                ds_TmptranstrfList.getCellData(i, "arvDistrictCd"),
                "T",
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                "도착지,도착지코드,도착지명");

            if (rtnList == null) {
                ds_tariff.setCellData(tRow, "arvDistrictCd", "");
                ds_tariff.setCellData(tRow, "arvDistrictNm", "");
                await $c.gus.cfAlertMsg(scwin.MSG_SD_ERR_003, [String(i + 1), "도착권역"]);
                return false;
            } else {
                ds_tariff.setCellData(tRow, "arvDistrictCd", rtnList[0]);
                ds_tariff.setCellData(tRow, "arvDistrictNm", rtnList[1]);
            }
        } else if (ds_TmptranstrfList.getCellData(i, "arvDistrictNm") != "") {
            let rtnList = $c.gus.cfCommonPopUp('retrieveDistrictList_tpro',
                ds_TmptranstrfList.getCellData(i, "arvDistrictNm"),
                ds_TmptranstrfList.getCellData(i, "arvDistrictNm"),
                "T",
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                "도착지,도착지코드,도착지명");

            if (rtnList == null) {
                ds_tariff.setCellData(tRow, "arvDistrictCd", "");
                ds_tariff.setCellData(tRow, "arvDistrictNm", "");
