scwin.sbm_selpchItemCd_submitdone = async function(e) {
    if (ds_selpchItemCd.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["요율항목"]);
        scwin.f_Close();
    } else {
        // TODO: sbm_contractWorkPath에 sysCd=CtrtTrfEBC, queryId=retrieveCtrtTransWrkPathList, param1=strCtrtNo, param2=selpchItemCd, param3=0 파라미터 전달 필요
        await $c.sbm.execute(sbm_contractWorkPath);
        $c.gus.cfChangeCdNmFormat(ds_contractWorkPath, "ctrtWrkPathSeq", "ctrtWrkPathNm");
    }
    // TODO: sbm_EqNrmCd에 sysCd=DsCommonEBC, queryId=retriveEqNrmTotalList 파라미터 전달 필요
    await $c.sbm.execute(sbm_EqNrmCd);
};

