scwin.ds_ctrtBase_onloadcompleted = async function(e) {
    let rowCnt = ds_ctrtBase.getRowCount();
    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["계약기본정보"]);
        scwin.f_Close();
    } else {
        let bizDivCntrYn = ds_ctrtBase.getCellData(ds_ctrtBase.getRowPosition(), "bizDivCntrYn");
        let bizDivBulkYn = ds_ctrtBase.getCellData(ds_ctrtBase.getRowPosition(), "bizDivBulkYn");

        let showCntr = (bizDivCntrYn == "true" || bizDivCntrYn == "1" || bizDivCntrYn == "Y");
        let showBulk = (bizDivBulkYn == "true" || bizDivBulkYn == "1" || bizDivBulkYn == "Y");

        // TODO: gr_tariff 컬럼 show/hide — transCondCd, cntrWtCondCd는 body에 없으므로 생략
        // gr_tariff.setColumnVisible("eqKndCd", showBulk);
        // gr_tariff.setColumnVisible("eqNrmCd", showBulk);
        // gr_tariff.setColumnVisible("trfAdptCd", showBulk);
        // gr_tariff.setColumnVisible("wrkStHh", showBulk);
        // gr_tariff.setColumnVisible("wrkEndHh", showBulk);

        scwin.f_retrieve();
    }
};

