scwin.gr_tariff_oncloseup = async function(rowIndex, columnIndex, columnId) {
    switch (columnId) {
        case "eqKndCd":
            // TODO: ds_EqNrmCd filter 처리 — WebSquare dataList filter API 사용 필요
            let v_eqKndCd = ds_tariff.getCellData(ds_tariff.getRowPosition(), "eqKndCd");
            if (ds_tariff.getRowCount() > 0 && v_eqKndCd != "") {
                ds_EqNrmCd.setFilterExpression("upperCd == '" + v_eqKndCd + "'");
            } else {
                ds_EqNrmCd.removeFilterExpression();
            }
            break;
        default:
            break;
    }
};

